mapper.select:
SELECT b.id, a.name, a.client_id, a.secret_key, b.func_code, c.name as funcName, c.is_async FROM data_app a, data_function_authority b, data_function c WHERE a.client_id = b.client_id AND b.func_code = c.func_code AND a.db_status = 1 AND b.db_status = 1 AND c.db_status = 1
and a.client_id = #{params.clientId}
order by a.id,c.func_code
